class Solution {
    public int maxScore(int[] nums) {
        Arrays.sort(nums);
        int n = nums.length / 2;
        int[] freq = new int[10007];
        for (int num : nums) {
            freq[num]++;
        }
        int maxScore = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= 10006; j++) {
                if (freq[j] >= 2) {
                    maxScore = Math.max(maxScore, i * j);
                    freq[j]--;
                    break;
                }
                for (int k = j + j; k <= 10006; k += j) {
                    if (freq[k] >= 2) {
                        maxScore = Math.max(maxScore, i * j);
                        freq[k] -= 2;
                        freq[j]--;
                        break;
                    }
                }
            }
        }
        return maxScore;
    }
}
